 1	import * as React from 'react';
 2	import _ from 'lodash';
 3	import { kialiStyle } from 'styles/StyleUtils';
 4	import { Responses } from '../../types/Graph';
 5	import { summaryTitle } from 'pages/Graph/SummaryPanelCommon';
 6	import { Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 7	
 8	const tableStyle = kialiStyle({
 9	  $nest: {
10	    '& tr > *': {
11	      paddingLeft: 0,
12	      paddingRight: 0
13	    },
14	    '& tbody > tr:last-child': {
15	      borderBottom: 0
16	    }
17	  }
18	});
19	
20	const noInfoStyle = kialiStyle({
21	  marginTop: '0.5rem'
22	});
23	
24	type ResponseHostsTableProps = {
25	  responses: Responses;
26	  title: string;
27	};
28	
29	interface Row {
30	  code: string;
31	  host: string;
32	  key: string;
33	  val: string;
34	}
35	
36	export const ResponseHostsTable: React.FC<ResponseHostsTableProps> = (props: ResponseHostsTableProps) => {
37	  const getRows = (responses: Responses): Row[] => {
38	    const rows: Row[] = [];
39	    _.keys(responses).forEach(code => {
40	      _.keys(responses[code].hosts).forEach(h => {
41	        rows.push({ key: `${code} ${h}`, code: code, host: h, val: responses[code].hosts[h] });
42	      });
43	    });
44	
45	    return rows;
46	  };
47	
48	  const rows = getRows(props.responses);
49	
50	  return (
51	    <>
52	      {rows.length > 0 ? (
53	        <>
54	          <div className={summaryTitle}>{props.title}</div>
55	
56	          <Table className={tableStyle}>
57	            <Thead>
58	              <Tr>
59	                <Th dataLabel="Code" width={20} textCenter>
60	                  Code
61	                </Th>
62	                <Th dataLabel="Host" width={50} textCenter>
63	                  Host
64	                </Th>
65	                <Th dataLabel="% Req" width={30} textCenter>
66	                  % Req
67	                </Th>
68	              </Tr>
69	            </Thead>
70	
71	            <Tbody>
72	              {rows.map(row => (
73	                <Tr key={row.key}>
74	                  <Td dataLabel="Code" textCenter>
75	                    {row.code}
76	                  </Td>
77	                  <Td dataLabel="Host" modifier="truncate" textCenter>
78	                    {row.host}
79	                  </Td>
80	                  <Td dataLabel="% Req" textCenter>
81	                    {row.val}
82	                  </Td>
83	                </Tr>
84	              ))}
85	            </Tbody>
86	          </Table>
87	        </>
88	      ) : (
89	        <div className={noInfoStyle}>No Host Information Available</div>
90	      )}
91	    </>
92	  );
93	};

